//! H.264 bitstream primitives: BitWriter, Exp-Golomb, NAL/AnnexB/AVCC packing,
//! SPS/PPS (Constrained Baseline), I-slice header, I_PCM macroblock writer.
//!
//! Pure Rust, `std`+`alloc` only. No external crates, no threads, no ffmpeg.
//! wasm32-safe. This is the entropy/syntax core for an ALL-INTRA H.264 encoder
//! that codes every macroblock as I_PCM (raw samples) — no transform, no CAVLC,
//! no intra prediction — yielding a fully valid, decodable H.264 stream.

/// MSB-first bit writer with byte accumulation.
pub struct BitWriter {
    bytes: Vec<u8>,
    cur: u8,
    nbits: u32, // number of bits currently filled in `cur` (0..=7)
}

impl BitWriter {
    pub fn new() -> Self {
        BitWriter {
            bytes: Vec::new(),
            cur: 0,
            nbits: 0,
        }
    }

    /// Write a single bit (only the LSB of `b` is used).
    pub fn put_bit(&mut self, b: u32) {
        self.cur = (self.cur << 1) | ((b & 1) as u8);
        self.nbits += 1;
        if self.nbits == 8 {
            self.bytes.push(self.cur);
            self.cur = 0;
            self.nbits = 0;
        }
    }

    /// Write the `n` least-significant bits of `val`, MSB-first.
    pub fn put_bits(&mut self, val: u32, n: u32) {
        debug_assert!(n <= 32);
        let mut i = n;
        while i > 0 {
            i -= 1;
            self.put_bit((val >> i) & 1);
        }
    }

    /// Unsigned Exp-Golomb code.
    ///
    /// codeNum = v; the code is a prefix of `leadingZeros` zero bits, a `1`,
    /// then `leadingZeros` info bits encoding (v + 1 - 2^leadingZeros).
    pub fn put_ue(&mut self, v: u32) {
        // x = v + 1; number of bits in x; emit (bits-1) leading zeros then x itself.
        let x = (v as u64) + 1;
        let bits = 64 - x.leading_zeros(); // position of the top set bit
        let leading_zeros = bits - 1;
        for _ in 0..leading_zeros {
            self.put_bit(0);
        }
        // emit x with `bits` bits, MSB-first
        let mut i = bits;
        while i > 0 {
            i -= 1;
            self.put_bit(((x >> i) & 1) as u32);
        }
    }

    /// Signed Exp-Golomb code: maps v -> codeNum via the standard zig-zag,
    /// then encodes as ue. se(0)=ue(0), se(1)=ue(1), se(-1)=ue(2), se(2)=ue(3), ...
    pub fn put_se(&mut self, v: i32) {
        let code_num: u32 = if v <= 0 {
            (-(v as i64) * 2) as u32
        } else {
            ((v as i64) * 2 - 1) as u32
        };
        self.put_ue(code_num);
    }

    /// Pad the current partial byte with zero bits to reach a byte boundary.
    pub fn align_to_byte(&mut self) {
        while self.nbits != 0 {
            self.put_bit(0);
        }
    }

    /// Consume the writer and return the underlying bytes. Any partial final
    /// byte is flushed (zero-padded) — callers that need exact alignment should
    /// have called `align_to_byte` / written an RBSP trailing bit first.
    pub fn into_bytes(mut self) -> Vec<u8> {
        if self.nbits != 0 {
            self.cur <<= 8 - self.nbits;
            self.bytes.push(self.cur);
            self.cur = 0;
            self.nbits = 0;
        }
        self.bytes
    }
}

impl Default for BitWriter {
    fn default() -> Self {
        Self::new()
    }
}

/// Write the RBSP trailing bits: a stop bit `1` followed by zero alignment.
fn rbsp_trailing(w: &mut BitWriter) {
    w.put_bit(1);
    w.align_to_byte();
}

/// Emulation prevention: turn an RBSP into an EBSP by inserting an
/// emulation_prevention_three_byte (0x03) after any 0x00 0x00 followed by a
/// byte in {0x00, 0x01, 0x02, 0x03}. (H.264 Annex B / 7.4.1.)
pub fn emulation_escape(rbsp: &[u8]) -> Vec<u8> {
    let mut out = Vec::with_capacity(rbsp.len() + rbsp.len() / 64 + 4);
    let mut zeros = 0usize; // count of consecutive trailing 0x00 already emitted
    for &b in rbsp {
        if zeros >= 2 && b <= 0x03 {
            out.push(0x03);
            zeros = 0;
        }
        out.push(b);
        if b == 0x00 {
            zeros += 1;
        } else {
            zeros = 0;
        }
    }
    out
}

/// Build a NAL unit (no start code): one header byte
/// (forbidden_zero_bit=0, nal_ref_idc, nal_unit_type) followed by the
/// emulation-escaped RBSP.
pub fn nal_unit(nal_ref_idc: u8, nal_type: u8, rbsp: &[u8]) -> Vec<u8> {
    let header = ((nal_ref_idc & 0x03) << 5) | (nal_type & 0x1f);
    let mut out = Vec::with_capacity(1 + rbsp.len() + 8);
    out.push(header);
    out.extend_from_slice(&emulation_escape(rbsp));
    out
}

#[inline]
fn ceil_div(a: u32, b: u32) -> u32 {
    (a + b - 1) / b
}

/// The minimum H.264 level_idc whose MaxFrameSize (in macroblocks) admits a
/// `width`×`height` frame. A 4K frame (3840×2160 = 32400 MBs) needs Level 5.1;
/// declaring a too-low level (the old hardcoded 3.1, max 3600 MBs ≈ 720p) makes
/// conformant decoders reject 1080p+ — fatal for the 4K goal.
pub fn h264_level_for(width: u32, height: u32) -> u32 {
    let mbs = ceil_div(width, 16) * ceil_div(height, 16);
    // (level_idc, MaxFS) pairs from H.264 Table A-1.
    const TABLE: &[(u32, u32)] = &[
        (30, 1620),   // 720×480
        (31, 3600),   // 1280×720
        (32, 5120),   //
        (40, 8192),   // 1920×1080
        (42, 8704),   //
        (50, 22080),  // 2560×1600
        (51, 36864),  // 4096×2304 — covers 3840×2160 (4K)
        (52, 36864),  // 4K @ 60
    ];
    for &(lvl, max_fs) in TABLE {
        if mbs <= max_fs {
            return lvl;
        }
    }
    60 // Level 6.0 (8K)
}

/// Constrained Baseline SPS NAL (nal_type=7, profile_idc=66).
pub fn build_sps(width: u32, height: u32) -> Vec<u8> {
    let mbw = ceil_div(width, 16);
    let mbh = ceil_div(height, 16);

    let mut w = BitWriter::new();

    // profile_idc = 66 (Baseline)
    w.put_bits(66, 8);
    // constraint_set0_flag=1, constraint_set1_flag=1, set2=0, set3=0, set4=0, set5=0, reserved 2 bits=0
    w.put_bit(1); // set0
    w.put_bit(1); // set1
    w.put_bit(0); // set2
    w.put_bit(0); // set3
    w.put_bit(0); // set4
    w.put_bit(0); // set5
    w.put_bits(0, 2); // reserved_zero_2bits
    // level_idc derived from resolution (4K ⇒ 51) — never reject the stream.
    w.put_bits(h264_level_for(width, height), 8);

    w.put_ue(0); // seq_parameter_set_id
    // (profile 66 has no chroma_format_idc etc. in the SPS)
    w.put_ue(0); // log2_max_frame_num_minus4
    w.put_ue(0); // pic_order_cnt_type
    w.put_ue(0); // log2_max_pic_order_cnt_lsb_minus4 (since poc type == 0)
    w.put_ue(1); // max_num_ref_frames
    w.put_bit(0); // gaps_in_frame_num_value_allowed_flag

    w.put_ue(mbw - 1); // pic_width_in_mbs_minus1
    w.put_ue(mbh - 1); // pic_height_in_map_units_minus1
    w.put_bit(1); // frame_mbs_only_flag = 1
    // (frame_mbs_only_flag==1, so no mb_adaptive_frame_field_flag)
    w.put_bit(1); // direct_8x8_inference_flag = 1

    // frame_cropping
    let crop = (width % 16 != 0) || (height % 16 != 0);
    if crop {
        w.put_bit(1); // frame_cropping_flag = 1
        let crop_right = (16 * mbw - width) / 2;
        let crop_bottom = (16 * mbh - height) / 2;
        w.put_ue(0); // frame_crop_left_offset
        w.put_ue(crop_right); // frame_crop_right_offset
        w.put_ue(0); // frame_crop_top_offset
        w.put_ue(crop_bottom); // frame_crop_bottom_offset
    } else {
        w.put_bit(0); // frame_cropping_flag = 0
    }

    w.put_bit(0); // vui_parameters_present_flag = 0

    rbsp_trailing(&mut w);
    let rbsp = w.into_bytes();
    nal_unit(3, 7, &rbsp)
}

/// PPS NAL (nal_type=8), CAVLC, single slice group, no extras.
pub fn build_pps() -> Vec<u8> {
    let mut w = BitWriter::new();

    w.put_ue(0); // pic_parameter_set_id
    w.put_ue(0); // seq_parameter_set_id
    w.put_bit(0); // entropy_coding_mode_flag = 0 (CAVLC)
    w.put_bit(0); // bottom_field_pic_order_in_frame_present_flag
    w.put_ue(0); // num_slice_groups_minus1
    w.put_ue(0); // num_ref_idx_l0_default_active_minus1
    w.put_ue(0); // num_ref_idx_l1_default_active_minus1
    w.put_bit(0); // weighted_pred_flag
    w.put_bits(0, 2); // weighted_bipred_idc
    w.put_se(0); // pic_init_qp_minus26
    w.put_se(0); // pic_init_qs_minus26
    w.put_se(0); // chroma_qp_index_offset
    w.put_bit(0); // deblocking_filter_control_present_flag
    w.put_bit(0); // constrained_intra_pred_flag
    w.put_bit(0); // redundant_pic_cnt_present_flag

    rbsp_trailing(&mut w);
    let rbsp = w.into_bytes();
    nal_unit(3, 8, &rbsp)
}

/// Fetch a luma sample with edge replication (clamp coords to frame extent).
#[inline]
fn luma_at(y: &[u8], width: u32, height: u32, px: u32, py: u32) -> u8 {
    let cx = px.min(width - 1);
    let cy = py.min(height - 1);
    y[(cy * width + cx) as usize]
}

/// Fetch a chroma sample with edge replication. cw/ch are chroma plane dims.
#[inline]
fn chroma_at(c: &[u8], cw: u32, ch: u32, px: u32, py: u32) -> u8 {
    let cx = px.min(cw - 1);
    let cy = py.min(ch - 1);
    c[(cy * cw + cx) as usize]
}

/// Encode a complete IDR coded slice NAL (nal_type=5, nal_ref_idc=3) where
/// every macroblock is I_PCM. Input is planar YUV420p, 8-bit:
/// `y` is width*height, `u`/`v` are (width/2)*(height/2).
pub fn encode_idr_ipcm(
    y: &[u8],
    u: &[u8],
    v: &[u8],
    width: u32,
    height: u32,
    idr_pic_id: u32,
) -> Vec<u8> {
    let mbw = ceil_div(width, 16);
    let mbh = ceil_div(height, 16);
    let cw = width / 2;
    let ch = height / 2;

    let mut w = BitWriter::new();

    // --- slice header ---
    w.put_ue(0); // first_mb_in_slice
    w.put_ue(7); // slice_type = 7 (I, applies to all slices in the picture)
    w.put_ue(0); // pic_parameter_set_id
    w.put_bits(0, 4); // frame_num, u(4) (log2_max_frame_num_minus4=0 -> 4 bits)
    // IdrPicFlag is true (nal_type 5) -> idr_pic_id present
    w.put_ue(idr_pic_id); // idr_pic_id
    w.put_bits(0, 4); // pic_order_cnt_lsb, u(4) (log2_max_poc_lsb_minus4=0 -> 4 bits)
    // dec_ref_pic_marking for IDR: no_output_of_prior_pics_flag, long_term_reference_flag
    w.put_bit(0); // no_output_of_prior_pics_flag
    w.put_bit(0); // long_term_reference_flag
    w.put_se(0); // slice_qp_delta

    // --- macroblocks, raster order ---
    for mby in 0..mbh {
        for mbx in 0..mbw {
            w.put_ue(25); // mb_type = 25 (I_PCM)

            // pcm_alignment_zero_bit until byte-aligned
            w.align_to_byte();

            // 256 luma samples (16x16), raster order within the MB
            let base_x = mbx * 16;
            let base_y = mby * 16;
            for ry in 0..16u32 {
                for rx in 0..16u32 {
                    let s = luma_at(y, width, height, base_x + rx, base_y + ry);
                    w.put_bits(s as u32, 8);
                }
            }

            // 64 Cb samples (8x8)
            let cbase_x = mbx * 8;
            let cbase_y = mby * 8;
            for ry in 0..8u32 {
                for rx in 0..8u32 {
                    let s = chroma_at(u, cw, ch, cbase_x + rx, cbase_y + ry);
                    w.put_bits(s as u32, 8);
                }
            }
            // 64 Cr samples (8x8)
            for ry in 0..8u32 {
                for rx in 0..8u32 {
                    let s = chroma_at(v, cw, ch, cbase_x + rx, cbase_y + ry);
                    w.put_bits(s as u32, 8);
                }
            }
            // After I_PCM the writer is byte-aligned again; no end_of_macroblock flag
            // is coded under CAVLC, so proceed directly to the next MB.
        }
    }

    rbsp_trailing(&mut w);
    let rbsp = w.into_bytes();
    nal_unit(3, 5, &rbsp)
}

/// AVCC-style sample: each NAL prefixed with its 4-byte big-endian length.
pub fn avcc_sample(nals: &[Vec<u8>]) -> Vec<u8> {
    let mut out = Vec::new();
    for nal in nals {
        let len = nal.len() as u32;
        out.extend_from_slice(&len.to_be_bytes());
        out.extend_from_slice(nal);
    }
    out
}

/// Annex B framing: 0x00000001 start code followed by the NAL.
pub fn annexb(nal: &[u8]) -> Vec<u8> {
    let mut out = Vec::with_capacity(4 + nal.len());
    out.extend_from_slice(&[0x00, 0x00, 0x00, 0x01]);
    out.extend_from_slice(nal);
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Render a BitWriter's bits as a string of '0'/'1' for the exact bits written
    /// (before any final-byte zero padding).
    fn bits_string(val_writer: impl FnOnce(&mut BitWriter)) -> String {
        // We reconstruct the bit string by tracking via a fresh writer plus a
        // parallel probe: easiest is to write into a writer and read flushed bytes,
        // but partial bits get zero-padded. Instead use a counting wrapper.
        let mut w = BitWriter::new();
        val_writer(&mut w);
        let nbits_partial = w.nbits;
        let partial = w.cur;
        let bytes = {
            // clone-free: emulate into_bytes but remember exact bit count
            let mut b = w.bytes.clone();
            if nbits_partial != 0 {
                b.push(partial << (8 - nbits_partial));
            }
            b
        };
        let total_bits = bytes.len() * 8 - if nbits_partial != 0 { (8 - nbits_partial) as usize } else { 0 };
        let mut s = String::new();
        for i in 0..total_bits {
            let byte = bytes[i / 8];
            let bit = (byte >> (7 - (i % 8))) & 1;
            s.push(if bit == 1 { '1' } else { '0' });
        }
        s
    }

    #[test]
    fn ue_known_values() {
        assert_eq!(bits_string(|w| w.put_ue(0)), "1");
        assert_eq!(bits_string(|w| w.put_ue(1)), "010");
        assert_eq!(bits_string(|w| w.put_ue(2)), "011");
        assert_eq!(bits_string(|w| w.put_ue(3)), "00100");
        assert_eq!(bits_string(|w| w.put_ue(4)), "00101");
    }

    #[test]
    fn se_known_values() {
        // se(0) -> ue(0) = "1"
        assert_eq!(bits_string(|w| w.put_se(0)), "1");
        // se(1) -> ue(1) = "010"
        assert_eq!(bits_string(|w| w.put_se(1)), "010");
        // se(-1) -> ue(2) = "011"
        assert_eq!(bits_string(|w| w.put_se(-1)), "011");
        // se(2) -> ue(3)
        assert_eq!(bits_string(|w| w.put_se(2)), "00100");
        // se(-2) -> ue(4)
        assert_eq!(bits_string(|w| w.put_se(-2)), "00101");
    }

    #[test]
    fn put_bits_msb_first() {
        assert_eq!(bits_string(|w| w.put_bits(0b101, 3)), "101");
        assert_eq!(bits_string(|w| w.put_bits(0xFF, 8)), "11111111");
        assert_eq!(bits_string(|w| w.put_bits(1, 4)), "0001");
    }

    #[test]
    fn emulation_escape_inserts_three() {
        // 0x00 0x00 0x00 -> 0x00 0x00 0x03 0x00
        assert_eq!(
            emulation_escape(&[0x00, 0x00, 0x00]),
            vec![0x00, 0x00, 0x03, 0x00]
        );
        // 0x00 0x00 0x01 -> 0x00 0x00 0x03 0x01
        assert_eq!(
            emulation_escape(&[0x00, 0x00, 0x01]),
            vec![0x00, 0x00, 0x03, 0x01]
        );
        // 0x00 0x00 0x02 -> escaped
        assert_eq!(
            emulation_escape(&[0x00, 0x00, 0x02]),
            vec![0x00, 0x00, 0x03, 0x02]
        );
        // 0x00 0x00 0x04 -> NOT escaped
        assert_eq!(
            emulation_escape(&[0x00, 0x00, 0x04]),
            vec![0x00, 0x00, 0x04]
        );
    }

    #[test]
    fn sps_nal_header() {
        let nal = build_sps(64, 48);
        assert!(!nal.is_empty());
        // header byte: forbidden_zero=0, nal_ref_idc=3, nal_type=7
        assert_eq!(nal[0] & 0x1f, 7); // nal_type
        assert_eq!((nal[0] >> 5) & 0x03, 3); // nal_ref_idc
        assert_eq!(nal[0] & 0x80, 0); // forbidden_zero_bit
    }

    #[test]
    fn sps_with_cropping() {
        // non-multiple-of-16 dimensions should still produce a valid NAL
        let nal = build_sps(70, 50);
        assert!(!nal.is_empty());
        assert_eq!(nal[0] & 0x1f, 7);
    }

    #[test]
    fn pps_nal_header() {
        let nal = build_pps();
        assert!(!nal.is_empty());
        assert_eq!(nal[0] & 0x1f, 8); // nal_type = PPS
        assert_eq!((nal[0] >> 5) & 0x03, 3);
    }

    #[test]
    fn idr_ipcm_luma_roundtrip() {
        // 16x16 solid frame, one macroblock.
        let width = 16u32;
        let height = 16u32;
        let y: Vec<u8> = (0..(width * height)).map(|i| (i % 251) as u8).collect();
        let u: Vec<u8> = vec![128u8; ((width / 2) * (height / 2)) as usize];
        let v: Vec<u8> = vec![200u8; ((width / 2) * (height / 2)) as usize];

        let nal = encode_idr_ipcm(&y, &u, &v, width, height, 0);
        assert!(!nal.is_empty());
        assert_eq!(nal[0] & 0x1f, 5); // IDR slice
        assert_eq!((nal[0] >> 5) & 0x03, 3); // nal_ref_idc

        // The slice header is small; the 256 PCM luma bytes appear after the
        // byte-aligned mb header. Rather than parse the header bit-exactly, locate
        // the luma run by reconstructing the RBSP and finding the aligned PCM block.
        // Simpler: verify the input luma bytes occur in-order as a contiguous run
        // within the (de-escaped) NAL payload.
        let payload = &nal[1..];
        // de-escape (reverse emulation): drop 0x03 after 0x00 0x00
        let mut rbsp = Vec::new();
        let mut zeros = 0;
        let mut i = 0;
        while i < payload.len() {
            let b = payload[i];
            if zeros >= 2 && b == 0x03 && i + 1 < payload.len() && payload[i + 1] <= 0x03 {
                // skip the emulation byte
                zeros = 0;
                i += 1;
                continue;
            }
            rbsp.push(b);
            if b == 0x00 {
                zeros += 1;
            } else {
                zeros = 0;
            }
            i += 1;
        }

        // Find the luma run: the 256 luma bytes are a contiguous subsequence
        // equal to `y`. Search for it.
        let found = rbsp
            .windows(y.len())
            .any(|win| win == y.as_slice());
        assert!(found, "I_PCM luma bytes should appear verbatim in the RBSP");

        // Chroma Cb (all 128) and Cr (all 200) runs should also be present.
        let cb = vec![128u8; 64];
        let cr = vec![200u8; 64];
        assert!(rbsp.windows(64).any(|win| win == cb.as_slice()));
        assert!(rbsp.windows(64).any(|win| win == cr.as_slice()));
    }

    #[test]
    fn annexb_and_avcc_framing() {
        let nal = build_pps();
        let ab = annexb(&nal);
        assert_eq!(&ab[0..4], &[0x00, 0x00, 0x00, 0x01]);
        assert_eq!(&ab[4..], &nal[..]);

        let sample = avcc_sample(&[nal.clone()]);
        let len = u32::from_be_bytes([sample[0], sample[1], sample[2], sample[3]]);
        assert_eq!(len as usize, nal.len());
        assert_eq!(&sample[4..], &nal[..]);
    }

    #[test]
    fn level_idc_scales_to_4k() {
        assert_eq!(h264_level_for(1280, 720), 31, "720p → L3.1");
        assert_eq!(h264_level_for(1920, 1080), 40, "1080p → L4.0");
        assert_eq!(h264_level_for(2560, 1600), 50, "1600p → L5.0");
        assert_eq!(h264_level_for(3840, 2160), 51, "4K → L5.1");
        // SPS byte layout: NAL header @ [0], profile_idc @ [1], constraints @ [2], level_idc @ [3].
        let sps4k = build_sps(3840, 2160);
        assert_eq!(sps4k[0], 0x67, "SPS NAL header");
        assert_eq!(sps4k[1], 66, "profile_idc Baseline");
        assert_eq!(sps4k[3], 51, "4K SPS declares level_idc 51 (was hardcoded 31 — would reject 4K)");
        assert_eq!(build_sps(1280, 720)[3], 31, "720p SPS keeps L3.1");
    }
}
